3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
19	    const sorted = (arr: [number, number][]) =>
20	      [...arr].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
21	    expect(sorted(result)).toEqual(sorted([[0, 0], [0, 1], [1, 0], [1, 1]]));
22	  });
23	  it.todo("should keep a live cell alive when it has 2 or 3 live neighbors (survival)");
24	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
25	  it.todo("should produce a stable block pattern (still life)");
